
	(1, 1, 'belfoods.com PT Sreeya Sewu Indonesia, Tbk', 'belfoodscom-pt-sreeya-sewu-indonesia-tbk.html', 'belfoods.com PT Sreeya Sewu Indonesia, Tbk', '', '', '', '', '', '', '<p style="text-align: center;" data-mce-style="text-align: center;"><span style="font-size: 14pt;" data-mce-style="font-size: 14pt;"><strong>Royal by Belfoods</strong> consistently innovates by presenting dish premium products berhigh quality that in line with current trends.</span><br><span style="font-size: 14pt;" data-mce-style="font-size: 14pt;">We believe in delivering a more premium and high-quality experience to consumers.</span><br><span style="font-size: 14pt;" data-mce-style="font-size: 14pt;">Oleh karena itu, Royal by Belfoods akan semakin dikenal sebagai merek that dapat diandalkan and memberikan </span><br><span style="font-size: 14pt;" data-mce-style="font-size: 14pt;">produk-produk berhigh quality that tetap mengikuti tren. <strong>Enjoy the delicious taste and premium quality products!</strong></span></p>', '', '2019-01-01 00:00:00', '', 'Belfoods mempersembahkan produk berkualitas sedelicious buatan Ibu, Enjoy the delicious taste and premium quality products!', '', 1, 999, 1, 'admin', '2026-03-03 13:56:09', '2026-03-03 13:56:09'),
