	(26, 8, 'Royal Cordon Bleu', 'royal-cordon-bleu.html', 'Royal Cordon Bleu', '', 'Net Weight : 250gr', '', '', '', '', '<p><b><span style="color: rgb(0, 0, 0);" data-mce-style="color: #000000;">Royal by Belfoods Chicken Gulung Isi Keju</span> </b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">brings quality dishes di your dining table. Saatnya membawa cita rasa ala Perancis ke rumah Anda with kedeliciousan dagingchicken asap and keju di dalam gulungan dada chicken that dibalut tepung roti renyah.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/royal/ROYAL-CordonBleu.png', '', '', 1, 8, 1, 'admin', '2026-03-09 14:21:36', '2026-03-09 14:21:36'),
