	(28, 9, 'Belfoods French Fries Shoestring', 'belfoods-french-fries-shoestring.html', 'Belfoods French Fries Shoestring', '', 'Net Weight : 500gr', '', '', '', '', '<p><b>Belfoods Kentang Goreng Beku</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> brings a favorite dish for the whole family. Made with selected potatoes, </span><b>Belfoods Kentang Goreng Beku</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> cocok for become cemilan and bring joy di segala suasana.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-Kentang-GorengShoestring-500gr.png', '', '', 1, 13, 1, 'admin', '2026-03-09 14:37:33', '2026-03-09 14:37:33'),
	(29, 9, 'Belfoods Crispy Fried Chicken', 'belfoods-crispy-fried-chicken.html', 'Belfoods Crispy Fried Chicken', '', 'Net Weight : 450gr ', '', '', '', '', '<p><b>Belfoods Chicken Goreng Renyah</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> brings a favorite dish for the whole family. Made from chicken utuh berkualitas with kenikmatan bumbu tepung that membalut chicken, menambah kedeliciousan di setiap gigitannya. </span><b>Belfoods Chicken Goreng Renyah</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> bring joy for hiandgan harian maupun event istimewa di rumah Anda.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-ChickenGorengRenyah-500gr.png', '', '', 1, 11, 1, 'admin', '2026-03-09 14:37:35', '2026-03-09 14:37:35'),
	(30, 9, 'Belfoods Spicy Wings', 'belfoods-spicy-wings.html', 'Belfoods Spicy Wings', '', 'Net Weight : 160gr  |  500gr ', '', '', '', '', '<p><b>Belfoods Sayap Chicken Berbumbu Pedas</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> brings a favorite dish for the whole family. Made dari sayap chicken pilihan that dipadukan with bumbu that begitu delicious hingga kedalamnya. </span><b>Belfoods Sayap Chicken Berbumbu Pedas</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> dijamin bring joy di segala suasana family anda.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-SpicyWings-500gr.png', '', '', 1, 10, 1, 'admin', '2026-03-09 14:37:36', '2026-03-09 14:37:36'),
	(31, 9, 'Belfoods Chicken Cocktail', 'belfoods-chicken-cocktail.html', 'Belfoods Chicken Cocktail', '', 'Net Weight : 400gr', '', '', '', '', '<p><b>Belfoods Sausage Chicken Cocktail</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> made with selected chicken meat. </span><b>Belfoods Sausage Chicken Cocktail</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> pre-cooked for your convenience. </span><b>Belfoods Sausage Chicken Cocktail</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> delicious to serve as a main course, snack, or party dish.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-ChickenCocktail-400gr.png', '', '', 1, 16, 1, 'admin', '2026-03-09 14:37:38', '2026-03-09 14:37:38'),
	(32, 9, 'Belfoods Chicken Nugget Stick', 'belfoods-chicken-nugget-stick.html', 'Belfoods Chicken Nugget Stick', '', 'Net Weight : 250gr  |  500gr  |  1000gr', '', '', '', '', '<p><b>Belfoods Chicken Stik</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> brings a favorite dish for the whole family. Made from daging chicken pilihan, tepung roti special and dibentuk memanjang that nikmat and delicious. </span><b>Belfoods Chicken Stik</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> cocok for dijadikan pelengkap makan and cemilan ringan for bring joy di rumah Anda.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-NuggetStick-500gr.png?_t=1773218389', '', '', 1, 5, 1, 'admin', '2026-03-09 14:37:40', '2026-03-09 14:37:40'),
	(33, 9, 'Belfoods Chicken Nugget', 'belfoods-chicken-nugget.html', 'Belfoods Chicken Nugget', '', 'Net Weight : 250gr  |  500gr  |  1000gr', '', '', '', '', '<p><b>Belfoods Nugget Chicken</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> brings a favorite dish for the whole family. Made with daging chicken pilihan and dilapisi tepung roti that gurih and renyah, </span><b>Belfoods Nugget Chicken</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> bring joy di segala suasana family Anda.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-ChickenNugget-500gr.png?_t=1773218378', '', '', 1, 4, 1, 'admin', '2026-03-09 14:37:42', '2026-03-09 14:37:42'),
	(34, 9, 'Belfoods Chicken Nugget Safari', 'belfoods-chicken-nugget-safari.html', 'Belfoods Chicken Nugget Safari', '', 'Net Weight : 450gr', '', '', '', '', '<p><b>Belfoods Nugget Chicken Safari</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> brings a favorite dish for the whole family. Kedeliciousannya merupakan perpaduan daging chicken pilihan and racikan that pas. </span><b>Belfoods Nugget Chicken Safari</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> bring joy dalam menyantap sambil mengenal bentuk-bentuk binatang.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-NuggetSafari-450gr.png', '', '', 1, 6, 1, 'admin', '2026-03-09 14:37:45', '2026-03-09 14:37:45'),
	(35, 9, 'Belfoods Chicken Meatball', 'belfoods-chicken-meatball.html', 'Belfoods Chicken Meatball', '', 'Net Weight : 100gr ', '', '', '', '', '<p><b>Belfoods Meatball Chicken</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> brings a favorite dish for the whole family. Diracik and diolah secara special becomekan rasa meatballnya begitu sedap pada setiap gigitan. </span><b>Belfoods Meatball Chicken</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> dapat dinikmati sebagai hiandgan meatball berkuah maupun cooked sebagai bahan pelengkap masakan lainnya. Present joy di rumah bersama </span><b>Belfoods Meatball Chicken</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-MeatballChicken-100grpng.png', '', '', 1, 18, 1, 'admin', '2026-03-09 14:37:47', '2026-03-09 14:37:47'),
	(36, 9, 'Belfoods Crispy Chicken Burger', 'belfoods-crispy-chicken-burger.html', 'Belfoods Crispy Chicken Burger', '', 'Net Weight : 315gr', '', '', '', '', '<p><b>Belfoods Burger Chicken Renyah</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> Mengbring dish favorite for the whole family.Made with daging chicken pilihan that dilapisi tepung roti that gurih and renyah. </span><b>Belfoods Burger Chicken Renyah</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> bring joy di setiap suasana family Anda.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-CrispyChickenBurger-450gr.png', '', '', 1, 15, 1, 'admin', '2026-03-09 14:37:49', '2026-03-09 14:37:49'),
	(37, 9, 'Belfoods Chicken Nugget BTS', 'belfoods-chicken-nugget-bts.html', 'Belfoods Chicken Nugget BTS', '', 'Net Weight : 450gr ', '', '', '', '', '<p><b>Belfoods Nugget Chicken "Be The Star (BTS)"</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">brings a favorite dish for the whole family. Made with daging chicken pilihan menggunakan bumbu pizza, dibalut with tepung roti that renyah and dibentuk menarik yaitu Bintang and Hati serta mengandung Kalsium membantu dalam pembentukan and mempertahankan kepadatan tulang and gigi. Membuat </span><b>Belfoods Nugget Chicken "Be The Star (BTS)" </b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">selalu dapat menceriakan your dining table.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-NuggetBTS-450gr.png', '', '', 1, 8, 1, 'admin', '2026-03-09 14:37:51', '2026-03-09 14:37:51'),
	(38, 10, 'Uenaaak Chicken Nugget Stick', 'uenaaak-chicken-nugget-stick.html', 'Uenaaak Chicken Nugget Stick', '', 'Net Weight : 500gr', '', '', '', '', '<p><b>Uenaaak Nugget Chicken Stik</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> made with daging chicken and selected ingredients. </span><b>Uenaaak Nugget Chicken Stik</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> dibungkus with tepung roti that renyah and pre-cooked for your convenience. </span><b>Uenaaak Nugget Chicken Stik </b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">delicious to serve as a main course, snack, or party dish.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/uenaaak/Uenaaak-NuggetChickenStick.png', '', '', 1, 3, 1, 'admin', '2026-03-09 15:12:05', '2026-03-09 15:12:05'),
