	(41, 11, 'Bonanza Meatball Sapi Gold', 'bonanza-meatball-sapi-gold.html', 'Bonanza Meatball Sapi Gold', '', 'Net Weight : 180gr  |  500gr  ', '', '', '', '', '<p><b>Bonanza Meatball Daging Sapi </b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">made with beef with racikan selected seasoning. Mengbring cita rasa khas meatball sapi with chewy texture and rasa that gurih, </span><b>Bonanza Meatball Daging Sapi</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> selalu become pilihan family Indonesia.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/bonanza/Bonanza-Gold-500g.png', '', '', 1, 1, 1, 'admin', '2026-03-09 15:17:48', '2026-03-09 15:17:48'),
