	(47, 2, '<b>Kentang Panggang Cheezy Bites</b>', 'kentang-panggang-cheezy-bites.html', '<b>Kentang Panggang Cheezy Bites</b>', '', '', '', '', '', '', '<p><span>kreasi deliciousnya cinta ibu, for kerluarga dalam hiandgan&nbsp;Kentang Panggang Cheezy Bites</span></p><h5>Ingredients</h5><p>1 bungkus<span>&nbsp;</span><a href="http://manifesto.co.id/clients/belfoods//products/royal/cheezy-bites/#sthash.inim2Ny8.dpbs" data-mce-href="http://manifesto.co.id/clients/belfoods//products/royal/cheezy-bites/#sthash.inim2Ny8.dpbs">Belfoods Royal Cheezy Bites</a>, goreng and tiriskan<br>400 gr kentang kukus,haluskan<br>1 tbsp mentega<br>100 gr grated cheese<br>50 ml krim kental<br>Merica and salt to taste<br>1 tsp peterseli chopped</p><h5>Instructions</h5><p>1.Campur kentang with mentega, krim kental, setengah bagian keju, peterseli, merica, and garam, aduk rata.<br>?2.Susun dalam mangkuk tahan panas lalu beri Belfoods Royal Cheezy Bitesdi atasnya, taburi with sisa grated cheese. Panggang sebentar hingga keju berubah warna and harum.<br>?3. Remove and serve panas with saus sambal</p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/wp-content/uploads/2013/06/kentang-panggang-370x1901.jpg', '', '', 1, 7, 0, 'admin', '2026-03-09 15:27:54', '2026-03-18 13:56:23'),
	(48, 2, 'New 09 Mar 2026, 15:28', 'new-09032026152808.html', '', '', '', '', '', '', '', '', '', '2019-01-01 00:00:00', '', '', '', 1, 999, 0, 'admin', '2026-03-09 15:28:08', '2026-03-10 14:14:34'),
	(49, 2, 'Tumis Mangga Spicy Wings', 'saute-mangga-spicy-wings.html', 'Tumis Mangga Spicy Wings', '', '', '', '', '', '', '<div class="span4 ingredient"><h5>ngredients</h5><ul><li>1 bungkus Belfoods Favorite Spicy Wings, goreng</li><li>3 tbsp minyak goreng</li><li>3 pcs cabai merah besar, iris serong</li><li>3 pcs cabai hijau besar, iris serong</li><li>6 butir bawang merah, finely sliced</li><li>3 cloves garlic, finely sliced</li><li>1 pcs tomat, diced</li><li>1 ruas jari jahe, memarkan</li><li>2 sheets daun jeruk</li><li>100 ml air</li><li>2 pcs mangga muda, iris korek api</li><li>Garam and sugar</li></ul><p>&nbsp;</p></div><div class="span4 instructions"><h5>Instructions</h5><ul><li>Heat minyak goreng lalu saute semua bumbu iris hingga harus. Tuang air, garam, and sugar, aduk rata.</li><li>Add Belfoods Favorite Spicy Wings, garam, and sugar, aduk rata lalu masukkan mangga muda sesaat sebelum diangkat.</li></ul></div>', '', '2019-01-01 00:00:00', 'https://belfoods.com/wp-content/uploads/2013/12/Tumis-Mangga-Spicy-Wings.jpg', '', '', 1, 999, 0, 'admin', '2026-03-09 15:28:13', '2026-03-16 15:40:37'),
	(50, 2, 'Ingredients 1 bungkus Belfoods Favorite Spicy Wings, goreng 3 tbsp minyak goreng 3 pcs cabai merah besar, iris serong 3 pcs cabai hijau besar, iris serong 6 butir bawang merah, finely sliced 3 cloves garlic, finely sliced 1 pcs tomat, poton', 'ingredients-1-bungkus-belfoods-favorite-spicy-wings-goreng-3-sendok-makan-minyak-goreng-3-pcs-cabai-merah-besar-iris-serong-3-pcs-cabai-hijau-besar-iris-serong-6-butir-bawang-merah-iris-halus-3-cloves-bawang-putih-iris-halus-1-pcs-tomat-potong-dadu', 'Ingredients 1 bungkus Belfoods Favorite Spicy Wings, goreng 3 tbsp minyak goreng 3 pcs cabai merah besar, iris serong 3 pcs cabai hijau besar, iris serong 6 butir bawang merah, finely sliced 3 cloves garlic, finely sliced 1 pcs tomat, poton', '', '', '', '', '', '', '<p>kreasi deliciousnya cinta ibu, for kerluarga dalam hiandgan&nbsp;Crepes Lipat Nugget Safari</p><div class="row"><div class="span4 ingredient"><h5>Ingredients</h5><p>150 gr terigu<br>275 ml liquid milk<br>50 gr gula halus<br>60 gr mentega cair<br>½ tsp baking powder<br>2 butir telur<br>1 bungkus<span>&nbsp;</span><a href="http://manifesto.co.id/clients/belfoods//products/favorite/chicken-nugget-safari/#sthash.9ivkI5pH.dpbs" data-mce-href="http://manifesto.co.id/clients/belfoods//products/favorite/chicken-nugget-safari/#sthash.9ivkI5pH.dpbs">Belfoods Favorite Safari</a>, goreng<br>100 gr selada<br>1 pcs wortel, iris korek api,rebus<br>50 ml mayones<br>3 tbsp saus tomat<br>2 tbsp saus sambal</p></div><div class="span4 instructions"><h5>Instructions</h5><p>Crepes:</p><p>1. Campur all-purpose flour,liquid milk, gula halus, mentega cair, baking powder, and telur,aduk hingga rata.<br>2. Heat pan datar lalu buat dadar tipis,lakukan hal that sama hingga bahan habis.<br>3. Siapkan satu sheets crepes,isi with selada, wortel, and Belfoods Favorite Safari.<br>4. Add with mayones,saus tomat, and saus sambal.</p></div></div>', '', '2019-01-01 00:00:00', 'https://belfoods.com/wp-content/uploads/2013/06/creppes-lipat-370x1903.jpg', '', '', 1, 999, 0, 'admin', '2026-03-09 15:28:16', '2026-03-09 16:47:22'),
	(51, 2, '<b>Mushroom Soup With Cheese Sausages</b>', 'mushroom-soup-with-cheese-sausages.html', '<b>Mushroom Soup With Cheese Sausages</b>', '', '', '', '', '', '', '<p><em>Serves 4</em><br></p><p><span style="font-size: 14pt; background-color: rgb(241, 196, 15);" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: rgb(0, 0, 0);" data-mce-style="color: #000000;">&nbsp;Ingredients : </span>&nbsp;</strong></span></p><ul><li>2 sdm mentega/margarin 30 gr onion, chopped</li><li>3 cloves garlic, chopped</li><li>100 gr jamur kancing segar, thinly sliced</li><li>2 sdm all-purpose flour</li><li>300 ml chicken stock</li><li>200 ml liquid milk</li><li>4 pcs <strong>ROYAL CHEESE FRANKFURTER</strong>, iris sesuai selera</li><li>1 sdm bumbu Itali bubuk</li><li>1 sdt garam</li><li>½ sdt ground pepper</li><li>2 sdm seledri chopped<br></li></ul><p><span style="font-size: 14pt; background-color: rgb(241, 196, 15);" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: rgb(0, 0, 0);" data-mce-style="color: #000000;">&nbsp;How to Make :</span>&nbsp;</strong></span></p><ol><li>Heat mentega/margarin, saute onion chopped and garlic chopped until fragrant. Add jamur kancing, saute sebentar.</li><li>Add all-purpose flour, aduk rata. Tuangkan chicken stock and liquid milk. Aduk sampai kental.</li><li>Add <strong>ROYAL CHEESE FRANKFURTER</strong>, bumbui with bumbu Itali, garam, and ground pepper, garam, and sugar. Cook until mendidih, angkat.</li><li>Serve sup while warm with taburan seledri chopped.</li></ol>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/content/Foto-Resep-Mushroom-Soup2.jpg', '', '', 1, 5, 1, 'admin', '2026-03-09 15:28:18', '2026-03-09 15:28:18'),
	(52, 2, '<b>Chicken Karaage With Honey Lemon Sauce</b>', 'chicken-karaage-with-honey-lemon-sauce.html', '<b>Chicken Karaage With Honey Lemon Sauce</b>', '', '', '', '', '', '', '<p><em>Serves 4</em></p><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;Ingredients : </span>&nbsp;</strong></span></p><ul><li><span>500 gr <strong>ROYAL CRISPY KARAAGE</strong></span></li><li><span>Cooking oil as needed</span></li><li><span>2 sdm scallions finely sliced</span><span><br><br></span><span>Honey Lemon Sauce</span>&nbsp;:</li><li><span>2 sdm margarin</span></li><li><span>3 cloves garlic, chopped</span></li><li><span>2 cm jahe muda, cut into long strips</span></li><li><span>250 ml chicken stock/air</span></li><li><span>2 sdm madu</span></li><li><span>¼ sdt ground pepper</span></li><li><span>½ sdt garam</span></li><li><span>1 sdm cornstarch, larutkan with sedikit air</span></li></ul><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;How to Make :</span>&nbsp;</strong></span></p><ol><li>Goreng <strong>ROYAL CRISPY KARAAGE</strong> with minyak goreng panas hingga kuning keemasan. Remove and drain. Sisihkan.</li><li><span>Saus madu lemon : Heat margarin, saute garlic and jahe muda until fragrant. Add chicken stock/air, madu, ground pepper, garam, and larutan maizena. Masak sambil aduk hingga saus kental.</span></li><li>Add chicken karage goreng and scallions. Aduk hingga chicken karaage rata with saus.<br></li><li><span>Remove and serve.</span></li></ol>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/content/Foto-Resep-KaraageLemon.jpg', '', '', 1, 4, 1, 'admin', '2026-03-09 15:28:20', '2026-03-09 15:28:20'),
	(53, 2, '<b>Caesar Salad Golden Fillet</b>', 'caesar-salad-golden-fillet.html', '<b>Caesar Salad Golden Fillet</b>', '', '', '', '', '', '', '<p><em>Serves 4</em></p><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;Ingredients : </span>&nbsp;</strong></span></p><ul><li><span>500 gr <strong>ROYAL GOLDEN FILLET</strong></span></li><li><span>10 pcs cherry tomatoes, belah dua</span></li><li><span>5 sheets lettuce leaves, iris kasar</span></li><li><span>2 sdm parmesan bubuk<br><br></span>Dressing:</li><li><span>150 ml minyak sayur</span></li><li><span>1 ½ sdm lemon juice</span></li><li><span>1/8 sdt garam</span></li><li><span>1/8 sdt coarsely ground black pepper</span></li><li><span>1 sdt sugar</span></li></ul><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;How to Make :</span>&nbsp;</strong></span></p><ol><li>Goreng <strong>ROYAL GOLDEN FILLET</strong> dalam minyak goreng panas hingga kuning keemasn. Remove and drain, kemudian potong sesuai selera.<br></li><li>Dressing: kocok minyak sayur, lemon juice, garam, merica and sugar with whisk hingga kental and putih.<br></li><li>Tata cherry tomatoes and lettuce leaves dalam piring saji. Add <strong>ROYAL GOLDEN FILLET</strong>, siram atasnya with dressing and taburi keju parmesan. Serve segera.</li></ol>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/content/Foto-Resep-CaesarGoldenFillet1.jpg', '', '', 1, 2, 1, 'admin', '2026-03-09 15:28:21', '2026-03-09 15:28:21'),
	(54, 2, '<b>Penne Cheezy Bites</b>', 'penne-cheezy-bites.html', '<b>Penne Cheezy Bites</b>', '', '', '', '', '', '', '<p>Serves 4<br>Ingredients:<br>500 gr BELFOODS ROYAL CHEEZY BITES<br>Cooking oil as needed</p><p>2 sdm margarin<br>30 gr onion, chopped<br>2 cloves garlic, chopped<br>3 pcs tomat merah, kupas, chopped<br>200 ml chicken stock.<br>½ sdt oregano bubuk<br>3 sdm saus tomat<br>¼ sdt merica<br>½ sdt garam<br>400 gr penne that sudah direbus matang seandg (al dente)<br>50 gr grated cheddar cheese</p><p>How to Make</p><ul><li>Goreng BELFOODS ROYAL CHEEZY BITES with minyak goreng panas hingga kuning keemasan. Remove and drain.</li><li>Heat margarin, saute onion and garlic until fragrant. Add tomat chopped, kaldu, oregano, saus tomat, merica, and garam. Cook until saus kental.</li><li>Add penne and BELFOODS ROYAL CHEEZY BITES. Aduk hingga rata with saus.</li><li>Serve with taburan grated cheddar cheese.</li></ul>', '', '2019-01-01 00:00:00', 'https://belfoods.com/wp-content/uploads/2019/10/PENNE-CHEEZY-BITES.jpg', '', '', 1, 3, 0, 'admin', '2026-03-09 15:28:23', '2026-03-18 13:48:54'),
	(55, 2, '<b>Honey Garlic With Sausages</b>', 'honey-garlic-with-sausages.html', '<b>Honey Garlic With Sausages</b>', '', '', '', '', '', '', '<p><em>Serves 4</em></p><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;Ingredients : </span>&nbsp;</strong></span></p><ul><li><span>3 sdm margarin</span></li><li>30 gr onion, thinly sliced</li><li><span>3 cloves garlic, chopped</span></li><li><span>100 gr kacang panjang, cut into 5 cm pieces</span></li><li><span>250 gr brokoli, potong-potong</span></li><li><span>2 pcs cabai merah, cut into long strips</span></li><li><span>4 pcs <strong>ROYAL BEEF FRANKFURTER</strong>, tambah sedikit keratin</span></li><li><span>2 ½ sdm madu</span></li><li><span>1 sdm kecap asin</span></li><li><span>½ sdt coarsely ground black pepper</span></li><li><span>¼ sdt garam</span></li><li><span>100 gr kacang panjang, cut into 5 cm pieces</span></li></ul><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;How to Make :</span>&nbsp;</strong></span></p><ol><li>Heat margarin, saute onion and garlic until fragrant. Add kacang panjang, brokoli, and cabai merah that dicut into long strips, saute sebentar hingga sayuran mulai matang.<br></li><li>Add <strong>ROYAL BEEF FRANKFURTER</strong>, saute hingga keratin sausage merekah.<br></li><li>Bumbui with madu, kecap asin, merica hitam, and garam. stir well.<br></li><li>Remove and serve hangat.<br></li></ol>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/content/Foto-Resep-Honey-Garlic1.jpg', '', '', 1, 1, 1, 'admin', '2026-03-09 15:28:34', '2026-03-09 15:28:34'),
	(56, 2, '<b>Bento Drumies Sushi Rice</b>', 'bento-drumies-sushi-rice.html', '<b>Bento Drumies Sushi Rice</b>', '', '', '', '', '', '', '<p><em>Serves 4</em></p><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;Ingredients : </span>&nbsp;</strong></span></p><ul><li><span>470 gr <strong>ROYAL CHICKEN NUGGET DRUMMIES</strong></span></li><li><span>Cooking oil as needed</span></li><li style="line-height: 1;" data-mce-style="line-height: 1;"><span>4 sheets nori, cut into 5 cm pieces</span><span><br><br>Butter Rice :<br></span></li><li><span>3 sdm mentega</span></li><li><span>3 cloves garlic, chopped</span></li><li><span>1 butir telur, kocok</span></li><li><span>500 gr fluffy rice</span></li><li><span>½ sdt garam</span></li><li><span>¼ sdt ground pepper</span></li></ul><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;How to Make :</span>&nbsp;</strong></span></p><ol><li>Goreng <span><strong>ROYAL CHICKEN NUGGET DRUMMIES</strong></span> with minyak goreng panas hingga kuning keemasan. Remove and drain.<br></li><li>Butter Rice: Heat mentega, saute garlic chopped until fragrant. Add telur kocok, aduk rata hingga bergumpal. Add nasi, garam, and ground pepper. Aduk hungga nasi rata with bumbu. Angkat.<br></li><li>Siapkan sesheets nori, ratakan butter rice di atasnya. Taruh <span><strong>ROYAL CHICKEN NUGGET DRUMMIES</strong></span> di bagian tengah, lalu gulung sushi sambil padatkan.<br></li><li>Serve and tata dalam boks bento bersama sayuran and pcs segar sesuai selera.<br></li></ol>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/content/Foto-Resep-Bento1.jpg', '', '', 1, 3, 1, 'admin', '2026-03-09 15:28:36', '2026-03-09 15:28:36'),
	(57, 12, 'Chicken Nanas ETC Opor Chicken', 'chicken-nanas-etc-opor-chicken.html', 'Chicken Nanas ETC Opor Chicken', '', 'Net Weight : 250gr', '', '', '', '', '<p><span style="font-weight: 400;" data-mce-style="font-weight: 400;">Seri Nusantara hadir sebagai pilihan andalan family, mengbring Rasa Warisan Otentik that kaya cita rasa. Dirancang for mendukung kepraktisan memasak with bahan terpilih, and memperkuat ikatan family melalui rasa khas Nusantara.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/chicken-nanas/ChickenNanas-EasyToCook-OporChicken.png?_t=1773300336', '', '', 1, 2, 1, 'admin', '2026-03-10 18:19:38', '2026-03-10 18:19:38'),
	(58, 12, 'Chicken Nanas ETC Renandg Chicken', 'chicken-nanas-etc-renandg-chicken.html', 'Chicken Nanas ETC Renandg Chicken', '', 'Net Weight : 200gr', '', '', '', '', '<p><span style="font-weight: 400;" data-mce-style="font-weight: 400;">Seri Nusantara hadir sebagai pilihan andalan family, mengbring Rasa Warisan Otentik that kaya cita rasa. Dirancang for mendukung kepraktisan memasak with bahan terpilih, and memperkuat ikatan family melalui rasa khas Nusantara.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/chicken-nanas/ChickenNanas-EasyToCook-RenandgChicken.png?_t=1773300338', '', '', 1, 1, 1, 'admin', '2026-03-10 18:19:39', '2026-03-10 18:19:39'),
	(59, 12, 'Chicken Nanas ETC Chicken Teriyaki', 'chicken-nanas-etc-chicken-teriyaki.html', 'Chicken Nanas ETC Chicken Teriyaki', '', 'Net Weight : 250gr', '', '', '', '', '<p><span style="font-weight: 400;" data-mce-style="font-weight: 400;">Made from Chicken Nanas and dibumbui with saus teriyaki that khas membuat </span><b>Chicken Nanas Chicken Teriyaki</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> become pilihan that delicious and praktis for the family.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/chicken-nanas/ChickenNanas-EasyToCook-Teriyaki.png?_t=1773300339', '', '', 1, 4, 1, 'admin', '2026-03-10 18:19:40', '2026-03-10 18:19:40'),
	(60, 12, 'Chicken Nanas ETC Chicken Katsu', 'chicken-nanas-etc-chicken-katsu.html', 'Chicken Nanas ETC Chicken Katsu', '', 'Net Weight : 250gr', '', '', '', '', '<p><span style="font-weight: 400;" data-mce-style="font-weight: 400;">Made from Chicken Nanas and dibalut breadcumb that renyah, becomekan </span><b>Chicken Nanas Chicken Katsu</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> become pilihan kaya protein that delicious and praktis.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/chicken-nanas/ChickenNanas-EasyToCook-Katsu.png?_t=1773300336', '', '', 1, 3, 1, 'admin', '2026-03-10 18:19:42', '2026-03-10 18:19:42'),
	(61, 9, 'Belfoods Chicken Nugget Crunchy', 'belfoods-chicken-nugget-crunchy.html', 'Belfoods Chicken Nugget Crunchy', '', 'Net Weight : 250gr | 500gr | 1000gr', '', '', '', '', '<p><b>Belfoods Nugget Chicken Crunchy</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> mengbring dish Favorit for the whole family. Made from daging chicken pilihan dibalut with tepung bumbu berbentuk bubble, mengbring sensasi renyah di setiap gigitan. Renyahnya </span><b>Belfoods Nugget Chicken Crunchy</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> membawa joy di setiap momen bersama family.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-NuggetCrunchy-450gr.png?_t=1773218384', '', '', 1, 1, 1, 'admin', '2026-03-11 15:47:14', '2026-03-11 15:47:14'),
	(62, 9, 'Belfoods Chicken Nugget Crunchy Stick', 'belfoods-chicken-nugget-crunchy-stick.html', 'Belfoods Chicken Nugget Crunchy Stick', '', 'Net Weight : 170gr  |  450gr ', '', '', '', '', '<p><b>Belfoods Nugget Chicken Stick Crunchy</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> mengbring dish Favorit for the whole family. Made from daging chicken pilihan dibalut with tepung bumbu berbentuk bubble, mengbring sensasi renyah di setiap gigitan. Renyahnya </span><b>Belfoods Nugget Chicken Stick Crunchy</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> membawa joy di setiap momen bersama family.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-NuggetCrunchyStick-450gr.png', '', '', 1, 2, 1, 'admin', '2026-03-11 15:50:43', '2026-03-11 15:50:43'),
	(63, 9, 'Belfoods Chicken Nugget Cornflakes', 'belfoods-chicken-nugget-cornflakes.html', 'Belfoods Chicken Nugget Cornflakes', '', 'Net Weight : 120gr  |  450gr', '', '', '', '', '<p><b>Belfoods Nugget Chicken Cornflakes </b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">mengbring dish Favorit for the whole family. Made from daging chicken pilihan dibalut with Cornflakes that renyah, mengbring sensasi renyah di setiap gigitan. Renyahnya </span><b>Belfoods Nugget Chicken Cornflakes </b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">membawa joy di setiap momen bersama family.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-NuggetCornflakes-450g.png', '', '', 1, 3, 1, 'admin', '2026-03-11 15:52:21', '2026-03-11 15:52:21'),
	(64, 9, 'Belfoods Chicken Nugget “S”', 'belfoods-chicken-nugget-s.html', 'Belfoods Chicken Nugget “S”', '', 'Net Weight : 170gr', '', '', '', '', '<p><b>Belfoods Nugget Chicken Bentuk S</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> brings a favorite dish for the whole family. Made with daging chicken pilihan and dilapisi tepung roti that gurih and renyah, </span><b>Belfoods Nugget Chicken Bentuk S</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> bring joy di segala suasana family Anda.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-Nugget-S-170gr.png', '', '', 1, 9, 1, 'admin', '2026-03-11 15:57:08', '2026-03-11 15:57:08'),
	(65, 9, 'Belfoods Chicken Nugget Ceria', 'belfoods-chicken-nugget-ceria.html', 'Belfoods Chicken Nugget Ceria', '', 'Net Weight : 170gr  |  450gr ', '', '', '', '', '<p><b>Belfoods Nugget Chicken Ceria</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> brings a favorite dish for the whole family. With komposisi daging chicken and selected ingredients lainnya that dibentuk lucu, membuat </span><b>Belfoods Nugget Chicken Ceria</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> selalu dapat menceriakan your dining table.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-NuggetCeria-450gr.png', '', '', 1, 7, 1, 'admin', '2026-03-11 15:58:10', '2026-03-11 15:58:10'),
	(66, 9, 'Belfoods Crispy Fried Chicken Pedaaaz', 'belfoods-crispy-fried-chicken-pedaaaz.html', 'Belfoods Crispy Fried Chicken Pedaaaz', '', 'Net Weight : 170gr  |  450gr ', '', '', '', '', '<p><b>Belfoods Chicken Goreng Renyah Pedas</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> brings a favorite dish bagi pencinta makanan pedas. Made from chicken utuh berkualitas dibalut tepung bumbu pedas, menambah kenikmatan with sensasi pedas and renyah di setiap gigitannya. Nikmatnya </span><b>Belfoods Chicken Goreng Renyah Pedas</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> for hiandgan harian maupun event istimewa di your home.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-ChickenGorengRenyahPedaaaz-500gr.png', '', '', 1, 12, 1, 'admin', '2026-03-11 16:05:37', '2026-03-11 16:05:37'),
	(67, 9, 'Belfoods French Fries', 'belfoods-french-fries.html', 'Belfoods French Fries', '', 'Net Weight : 500gr ', '', '', '', '', '<p><b>Belfoods Kentang Goreng Beku</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> brings a favorite dish for the whole family. Made with selected potatoes, </span><b>Belfoods Kentang Goreng Beku</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> cocok for become cemilan and bring joy di segala suasana.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-KentangGoreng-500gr.png', '', '', 1, 14, 1, 'admin', '2026-03-11 16:11:53', '2026-03-11 16:11:53'),
	(68, 9, 'Belfoods Chicken Sausage', 'belfoods-chicken-sausage.html', 'Belfoods Chicken Sausage', '', 'Net Weight : 200gr ', '', '', '', '', '<p><b>Belfoods Sausage Chicken</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> made with selected chicken meat. </span><b>Belfoods Sausage Chicken </b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">pre-cooked for your convenience. </span><b>Belfoods Sausage Chicken</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> delicious to serve as a main course, snack, or party dish.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-SausageChicken-200gr.png', '', '', 1, 17, 1, 'admin', '2026-03-11 16:16:39', '2026-03-11 16:16:39'),
